keyframesSample:
@keyframes scaleIn { 
  0% { opacity: 0; transform: scale(0.95) translateY(20px); }
  100% { opacity: 1; transform: scale(1) translateY(0px); }
}

@keyframes scaleOut { 
  0% { opacity: 1; transform: scale(1) translateY(0px); }
  100% { opacity: 0; transform: scale(0.95) translateY(20px); }
}
